svg.metadata:
{
  "diagram": "topology-chain-cascade",
  "title": "Line Topology — Cascade",
  "nodes": [
    {"id": "in0",          "role": "input"},
    {"id": "readGate",     "role": "and-gate"},
    {"id": "i0",           "role": "inhibitor",             "index": 0},
    {"id": "i1",           "role": "inhibitor",             "index": 1},
    {"id": "inhibitRight0","role": "inhibit-right-gate"}
  ],
  "edges": [
    {"id": "readGateToI0",     "source": "readGate", "target": "i0",         "kind": "chain"},
    {"id": "i0ToI1",           "source": "i0",       "target": "i1",         "kind": "chain"},
    {"id": "i1AckToReadGate",  "source": "i1",       "target": "readGate",   "kind": "feedback-ack"},
    {"id": "inputToReadGate",  "source": "in0",      "target": "readGate",   "kind": "chain"},
    {"id": "i0ToInhibitRight",         "source": "i0",           "target": "inhibitRight0","kind": "inhibit-in"},
    {"id": "i1ToInhibitRight",         "source": "i1",           "target": "inhibitRight0","kind": "inhibit-in"}
  ],
  "timing": {
    "cycleSeconds": 27,
    "steps": [
      {"t": 0.06, "event": "in0 fires"},
      {"t": 0.19, "event": "readGate fires"},
      {"t": 0.30, "event": "readGate value pulse traveling to i0"},
      {"t": 0.42, "event": "i0 fires"},
      {"t": 0.52, "event": "i0ToI1 value pulse departs i0"},
      {"t": 0.83, "event": "i0ToI1 value pulse arrives at i1"},
      {"t": 0.84, "event": "i1 fires"},
      {"t": 0.90, "event": "feedback ack arrives at readGate — cycle closes"}
    ]
  }
}
